from abc import ABC, abstractmethod

import numpy as np
from scipy.spatial import KDTree

from .geometry import (
    compute_length,
    compute_polygon_signed_area,
    compute_distance,
    change_frame,
    n_sphere_volume,
    compute_rotation_matrix,
    find_nearest,
    main_axis,
    are_oriented,
)
from .space import (
    Positioned,
    SpaceElement,
    Space,
    Circular,
    Direction,
    OrientedPositioned,
)


class Geometry(ABC):
    @abstractmethod
    def __iter__(self):
        pass

    @abstractmethod
    def to_dict(self) -> dict:
        pass

    @classmethod
    @abstractmethod
    def from_dict(cls, dictionary):
        pass

    @classmethod
    @abstractmethod
    def _coordinates_name_geo_json(cls) -> str:
        pass

    @classmethod
    def _coordinates_from_geo_json(cls, dictionary):
        return {cls._coordinates_name_geo_json(): dictionary["coordinates"]}

    @classmethod
    def parameters_from_geo_json(cls, dictionary):
        return cls._coordinates_from_geo_json(dictionary)

    @property
    @abstractmethod
    def dimension(self) -> int:
        pass

    @property
    @abstractmethod
    def empty(self) -> bool:
        pass

    @abstractmethod
    def _type_geo_json(self) -> str:
        pass

    @abstractmethod
    def _coordinates_geo_json(self) -> list:
        pass

    @property
    def __geo_interface__(self):
        return {
            "type": self._type_geo_json(),
            "coordinates": self._coordinates_geo_json(),
        }

    @abstractmethod
    def to_relation(self):
        pass


class PropertiesGeometry(Geometry):
    @abstractmethod
    def _properties_geo_json(self):
        pass

    @property
    def __geo_interface__(self):
        return {**super().__geo_interface__, "properties": self._properties_geo_json()}


class SubGeometry(PropertiesGeometry):
    @abstractmethod
    def _sub_type_geo_json(self):
        pass

    @abstractmethod
    def _sub_type_properties_geo_json(self):
        pass

    def _properties_geo_json(self):
        return {
            "subgeometry": {
                "type": self._sub_type_geo_json(),
                "properties": self._sub_type_properties_geo_json(),
            }
        }

    @classmethod
    def _sub_parameters_from_geo_json(cls, dictionary):
        return dictionary["properties"]["subgeometry"]["properties"]

    @classmethod
    def parameters_from_geo_json(cls, dictionary):
        return {
            **super().parameters_from_geo_json(dictionary),
            **cls._sub_parameters_from_geo_json(dictionary),
        }


class PointGeometry(Geometry):
    def __init__(self, origin):
        self.origin = np.array(origin, float)

    def __iter__(self):
        yield self.origin

    @property
    def dimension(self):
        return len(self.origin)

    @property
    def empty(self):
        return not self.dimension

    @classmethod
    def _coordinates_name_geo_json(cls):
        return "origin"

    def to_dict(self):
        return {self._coordinates_name_geo_json(): list(self.origin)}

    @classmethod
    def from_dict(cls, dictionary):
        return cls(**dictionary)

    def _type_geo_json(self):
        return "Point"

    def _coordinates_geo_json(self):
        return [float(coord) for coord in self.origin]

    def to_relation(self):
        return SpaceRelation([self.origin])


class Point(Positioned, SpaceElement, PointGeometry, ABC):
    @property
    def is_positioned(self):
        return True

    @classmethod
    def from_spatial(cls, spatial, local):
        return cls(spatial.to_point(local))

    def _is_valid(self, local):
        return local is True

    def find_local_nearest_from_point(self, point):
        return True

    def find_local_nearest(self, other):
        return True

    def _to_point(self, local):
        return self.origin

    def __repr__(self):
        return "{}({})".format(self.__class__.__name__, repr(self.origin))


class Vector(Point, Direction, OrientedPositioned):
    def __init__(self, origin, axis):
        Point.__init__(self, origin)
        Direction.__init__(self, axis)

    @classmethod
    def from_spatial(cls, spatial, local):
        return cls(spatial.to_point(local), spatial.to_axis(local))

    def __repr__(self):
        return "{}({}, {})".format(
            self.__class__.__name__, repr(self.origin), repr(self.axis)
        )


class Points(Geometry, ABC):
    def __init__(self, points):
        self.points = np.array(points)

    def __iter__(self):
        for point in self.points:
            yield point

    def __len__(self):
        return len(self.points)

    def __repr__(self):
        return "{}({})".format(self.__class__.__name__, self.points)

    def __str__(self):
        return "{}({})".format(self.__class__.__name__, len(self))

    @property
    def dimension(self):
        try:
            return self.points.shape[1]
        except IndexError:
            raise ValueError("Cannot determine dimension of empty list of points")

    @property
    def empty(self):
        return len(self) == 0

    @classmethod
    def from_dict(cls, dictionary):
        return cls(**dictionary)

    @classmethod
    def _coordinates_name_geo_json(cls):
        return "points"

    def to_dict(self):
        return {
            self._coordinates_name_geo_json(): [list(point) for point in self.points]
        }

    def _coordinates_geo_json(self):
        return [[float(coord) for coord in point] for point in self.points]

    def to_relation(self):
        return SpaceRelation(self.points)


class MultiPoint(Points):
    def _type_geo_json(self):
        return "MultiPoint"


class LineString(Points):
    def linear_length(self):
        return compute_length(self.points)

    def _type_geo_json(self):
        return "LineString"


class MultiLineString(Geometry):
    def __init__(self, lines):
        self.lines = lines

    def __iter__(self):
        for line in self.lines:
            for point in line:
                yield point

    def to_dict(self) -> dict:
        return {
            self._coordinates_name_geo_json(): [
                [list(point) for point in line] for line in self.lines
            ]
        }

    @classmethod
    def from_dict(cls, dictionary):
        return cls(**dictionary)

    @classmethod
    def _coordinates_name_geo_json(cls) -> str:
        return "lines"

    @property
    def dimension(self) -> int:
        try:
            return len(self.lines[0][0])
        except IndexError:
            raise ValueError("Cannot determine dimension of empty list of points")

    def __len__(self):
        return len(self.lines)

    @property
    def empty(self) -> bool:
        return len(self) == 0

    def _type_geo_json(self) -> str:
        return "MultiLineString"

    def _coordinates_geo_json(self) -> list:
        return [
            [[float(coord) for coord in point] for point in line] for line in self.lines
        ]

    def to_relation(self):
        return SpaceRelation(list(self))


class Polygon(Points):
    def perimeter(self):
        return compute_length(self.points, closed=True)

    def area(self):
        return abs(compute_polygon_signed_area(self.points[:, :2]))

    def _size(self, factor):
        perimeter = self.perimeter()
        determinant = perimeter**2 - 16.0 * self.area()
        if determinant < 0.0:
            raise AttributeError("Invalid polygon shape to compute feature")
        return (perimeter + factor * np.sqrt(determinant)) / 4.0

    def width(self):
        return self._size(-1)

    def length(self):
        return self._size(1)

    def _coordinates_geo_json(self):
        return [super()._coordinates_geo_json()]

    @classmethod
    def _coordinates_from_geo_json(cls, dictionary):
        return {
            name: coordinates[0]
            for name, coordinates in super()
            ._coordinates_from_geo_json(dictionary)
            .items()
        }

    def _type_geo_json(self):
        return "Polygon"


class Ball(Space, Circular, SpaceElement, PointGeometry, SubGeometry):
    def __init__(self, origin, radius):
        PointGeometry.__init__(self, origin)
        self.radius = radius

    @property
    def is_positioned(self):
        return True

    @property
    def is_radial(self) -> bool:
        return True

    @classmethod
    def from_spatial(cls, spatial, local):
        return cls(spatial.to_point(local), spatial.to_radius(local))

    def _sub_type_properties_geo_json(self):
        return {"radius": self.radius}

    def _sub_type_geo_json(self):
        return "Ball"

    def _to_radius(self, local):
        return self.radius - compute_distance(self.origin, local)

    def __contains__(self, point):
        distance = compute_distance(self.origin, point)
        # np.isclose is used to prevent float instability in project_point_on_contour method
        return np.isclose(distance, self.radius) or distance <= self.radius

    def project_point_on_contour(self, point):
        return (
            None
            if np.isclose(compute_distance(self.origin, point), 0.0)
            else change_frame(self.origin, point, self.radius)
        )

    def find_local_nearest(self, other):
        return self.find_local_nearest_from_point(other.origin)

    def volume(self):
        return n_sphere_volume(self.radius, len(self.origin))

    def __repr__(self):
        return "{}({}, {})".format(
            self.__class__.__name__, repr(self.origin), repr(self.radius)
        )


class OrientedBall(Ball, Direction, OrientedPositioned):
    def __init__(self, origin, radius, axis):
        Ball.__init__(self, origin, radius)
        Direction.__init__(self, axis)

    @classmethod
    def from_spatial(cls, spatial, local):
        return cls(
            spatial.to_point(local), spatial.to_radius(local), spatial.to_axis(local)
        )

    def __repr__(self):
        return "{}({}, {}, {})".format(
            self.__class__.__name__,
            repr(self.origin),
            repr(self.radius),
            repr(self.axis),
        )


class Frame(Point):
    def __init__(self, origin, angles):
        Point.__init__(self, origin)
        self.angles = np.array(angles, float)
        self.rotation = compute_rotation_matrix(self.angles)

    def to_local(self, points):
        return np.subtract(points, self.origin) @ self.rotation

    def to_global(self, local):
        return np.add(self.origin, local @ self.rotation.T)

    def __repr__(self):
        return "{}({}, {})".format(
            self.__class__.__name__, repr(self.origin), repr(self.angles)
        )


class SpaceRelation(Points, OrientedPositioned):
    def __init__(self, points):
        Points.__init__(self, points)
        self.centroid = (
            find_nearest(self.points, np.mean(self.points, axis=0))
            if len(self) > 0
            else None
        )
        self.tree = KDTree(self.points) if len(self) > 0 else None
        self.axis = main_axis(self.points) if are_oriented(self.points) else None

    @property
    def is_positioned(self):
        return self.tree is not None

    @property
    def is_oriented(self):
        return self.axis is not None

    def _find_local_nearest_from_point(self, point):
        return self.tree.query(point)[1]

    def find_local_nearest_from_point(self, point):
        return (
            self._find_local_nearest_from_point(point) if self.is_positioned else None
        )

    def find_local_nearest(self, other):
        raise NotImplementedError

    def _type_geo_json(self):
        raise NotImplementedError

    def _local_pair(self, other):
        self.check_positioned()
        index = self._find_local_nearest_from_point(other.centroid)
        other_index = other._find_local_nearest_from_point(self.points[index])
        return [index, other_index]

    def local_pair(self, other):
        # Reimplemented for optimization
        return (
            self._local_pair(other)
            if len(self) > len(other)
            else other._local_pair(self)[::-1]
        )

    def _to_point(self, local):
        return self.points[local]

    def _to_axis(self, local):
        self.check_oriented()
        return self.axis

    def _is_valid(self, local):
        return local in range(len(self))


GEOMETRIES = (Point, MultiPoint, LineString, Polygon, Ball)

GEOJSON = {geometry.__name__: geometry for geometry in GEOMETRIES}
